// Detect and normalize incoming channel
const body = $input.item.json.body || $input.item.json;

let channel = 'unknown';
let message = '';
let userId = '';
let metadata = {};

// WhatsApp detection
if (body.object === 'whatsapp_business_account' && body.entry) {
  channel = 'whatsapp';
  const msg = body.entry[0]?.changes[0]?.value?.messages?.[0];
  message = msg?.text?.body || '';
  userId = msg?.from || '';
  metadata = { messageId: msg?.id, timestamp: msg?.timestamp };
}
// Telegram detection
else if (body.message && body.message.chat) {
  channel = 'telegram';
  message = body.message.text || '';
  userId = body.message.from.id.toString();
  metadata = { chatId: body.message.chat.id, messageId: body.message.message_id, username: body.message.from.username };
}
// Email/Gmail detection
else if (body.from && body.subject) {
  channel = 'email';
  message = body.subject + '\n\n' + (body.body || body.textPlain || '');
  userId = body.from;
  metadata = { messageId: body.messageId, to: body.to, cc: body.cc };
}
// Direct API call
else if (body.query || body.message) {
  channel = 'api';
  message = body.query || body.message;
  userId = body.user_id || body.userId || 'anonymous';
  metadata = body.metadata || {};
}

return { channel, message, userId, metadata, timestamp: new Date().toISOString() };

// Parse intent safely with fallback
const raw = $input.item.json;
let intent = 'query';
let confidence = 0.5;
let details = {};

try {
  const content = raw.choices?.[0]?.message?.content || '{}';
  const parsed = typeof content === 'string' ? JSON.parse(content) : content;
  intent = parsed.intent || 'query';
  confidence = parsed.confidence || 0.5;
  details = parsed.details || {};
} catch (e) {
  // Default to query on parse error
  intent = 'query';
  confidence = 0.3;
}

return { intent, confidence, details, message: $('Channel Detector').item.json.message };

// Format response for the original channel
const channelData = $('Channel Detector').item.json;
const channel = channelData.channel;
const result = $input.item.json;

// Extract answer from various response formats
const answer = result.answer || result.response || result.result || result.final_response || result.interpretation || result.output || 'Désolé, je n\'ai pas pu traiter votre demande.';
const sources = result.sources || result.context || [];
const confidence = result.confidence || 0;

let formattedResponse = {};

switch (channel) {
  case 'whatsapp':
    formattedResponse = {
      messaging_product: 'whatsapp',
      to: channelData.userId,
      type: 'text',
      text: { body: answer }
    };
    break;
  case 'telegram':
    formattedResponse = {
      chat_id: channelData.metadata.chatId,
      text: answer,
      parse_mode: 'Markdown'
    };
    break;
  case 'email':
    formattedResponse = {
      to: channelData.userId,
      subject: 'Re: ' + (channelData.metadata.subject || 'Votre demande'),
      body: answer,
      inReplyTo: channelData.metadata.messageId
    };
    break;
  case 'api':
  default:
    formattedResponse = {
      success: true,
      channel,
      userId: channelData.userId,
      answer: answer,
      sources: sources,
      confidence: confidence,
      metadata: { timestamp: new Date().toISOString() }
    };
    break;
}

return formattedResponse;
